#include<bits/stdc++.h>
using namespace std;

#define ll long long

ll n,t,w[100100],dp[100001],ant=0;

int main(){
	cin>>n>>t;
	for(int i=1;i<=n;i++){
		cin>>w[i];
	}
	for(int i=1;i<=n;i++){
		for(int j=t;j>=w[i];j--){
			if(j>w[i]) dp[j]+=dp[j-w[i]];
            else if(j==w[i]) dp[j]+=1;
		}
	}cout<<dp[t];
	return 0;
}
